import 'bootstrap/dist/css/bootstrap.min.css';
import './styles.css';
import NavBar from './components/NavBar';
import Home from './components/';
import axios from 'axios';
import {useContext, useEffect, useState} from 'react';

const App = () => {
  const [meals, setMeals] = useState([]);

  useEffect(() => {
    axios.get(`https://www.themealdb.com/api/json/v1/1/search.php?f=a`).then((data) => setMeals(data)).catch((error) => console.log(error));

  },[])
  console.log(meals);
  return (
    <div>
      <NavBar />
      <Home />
    </div>
  );
}

export default App;
